parameters.jsCode:
return [{ json: {
  topic: 'GA4 Reporting fuer Agenturen',
  platform: 'linkedin',
  angle: 'Haeufige Reporting-Fehler und wie Sandbank sie reduziert',
  brand_tone: 'natuerlich, klar, authentisch, auf den Punkt'
}}];

const i = items[0].json;
const userPrompt = [
  `Topic: ${i.topic}`,
  `Platform: ${i.platform}`,
  `Angle: ${i.angle}`,
  `Tone: ${i.brand_tone}`,
  'Erstelle einen strukturierten Post mit Hook, Problem, Insight, Beispiel und CTA.',
  'Gib nur JSON mit Feldern title, body, cta und hashtags zurueck.'
].join('\n');
return [{ json: { userPrompt } }];

parameters.jsonBody:
={{ {
  model: $env.OLLAMA_MODEL || 'qwen3.5:27b',
  stream: false,
  messages: [
    { role: 'system', content: 'Du bist ein deutscher B2B-Social-Media-Copywriter. Kein Buzzword-Text. Nur belastbare Aussagen. Keine Gedankenkette, nur das Ergebnis.' },
    { role: 'user', content: $json.userPrompt }
  ],
  options: { temperature: 0.3, num_predict: 180, num_ctx: 1024 }
} }}

parameters.jsCode:
